const ws = new WebSocket(
  `${location.protocol === 'https:' ? 'wss' : 'ws'}://${location.host}/api/v1/ws/telemetry?device_id=dev-001`
);

ws.onopen = () => console.log('Connected to telemetry stream');

ws.onmessage = (event) => {
  const reading = JSON.parse(event.data);
  console.log(`${reading.device_id}: ${reading.metric} = ${reading.value}${reading.unit}`);
};

ws.onclose = (event) => {
  console.log(`Closed: ${event.code} ${event.reason}`);
};

ws.onerror = (err) => console.error('WebSocket error:', err);

const ws = new WebSocket(
  `${location.protocol === 'https:' ? 'wss' : 'ws'}://${location.host}/api/v1/ws/dashboard`
);

ws.onmessage = (event) => {
  const envelope = JSON.parse(event.data);
  switch (envelope.type) {
    case 'system_health':
      updateHealthWidget(envelope.data);
      break;
    case 'pipeline_stages':
      updatePipelineWidget(envelope.data);
      break;
    case 'alerts':
      handleNewAlert(envelope.data);
      break;
    case 'device_stats':
      updateDeviceCount(envelope.data);
      break;
    default:
      console.warn('Unknown envelope type:', envelope.type);
  }
};

ws.onclose = (event) => {
  console.log(`Dashboard WS closed: ${event.code}`);
  // Reconnect with backoff...
};
